mapper.select:
select id, comment_id, user_id, reaction_type, create_time
from comment_reaction
where user_id = #{userId}
  and comment_id = #{commentId}
limit 1

mapper.update:
update comment_reaction
set reaction_type = #{reactionType}
where id = #{id}

mapper.delete:
delete from comment_reaction
where user_id = #{userId}
  and comment_id = #{commentId}

mapper.select:
select comment_id as commentId, sum(case when reaction_type = 1 then 1 else 0 end) as likeCount, sum(case when reaction_type = 2 then 1 else 0 end) as dislikeCount, max(case when user_id = #{userId} then reaction_type else 0 end) as myReactionType from comment_reaction where comment_id in
#{id}
group by comment_id
